// ═══════════════════════════════════════════════════════════════
// PREPARAR DATOS - VERSIÓN OPTIMIZADA
// ═══════════════════════════════════════════════════════════════

const input = $input.first().json;

// ═══════════════════════════════════════════════════════════════
// 1. EXTRAER DATOS DEL CLIENTE
// ═══════════════════════════════════════════════════════════════
const email = (input.Email || input.email || '').toLowerCase().trim();
const nombre = input.Nombre || input.nombre || 'Cliente';
const telefono = input.Teléfono || input.telefono || '';

// Validación básica
if (!email || !email.includes('@')) {
  throw new Error(`Email inválido: ${email}`);
}

// ═══════════════════════════════════════════════════════════════
// 2. GENERAR ID DE PROCESO
// ═══════════════════════════════════════════════════════════════
const processId = `ONB-${Date.now().toString(36).toUpperCase()}-${Math.random().toString(36).substr(2, 4).toUpperCase()}`;

// ═══════════════════════════════════════════════════════════════
// 3. CONFIGURACIÓN DE ENLACES (EDITAR AQUÍ)
// ═══════════════════════════════════════════════════════════════
const config = {
  notionLink: "https://www.notion.so/Oficialmente-Haces-Parte-ca32b8d3e6504cf1897807f7144ffab4?source=copy_link",
  diagnosticoLink: "https://forms.gle/ATTxZfrDbiCdH9AG6",
  calendlyLink: "https://calendly.com/santix/sesion-1-1-s1"
};

// ═══════════════════════════════════════════════════════════════
// 4. RETORNAR DATOS CONSOLIDADOS
// ═══════════════════════════════════════════════════════════════
return [{
  json: {
    // Datos del cliente
    Email: email,
    Nombre: nombre,
    Teléfono: telefono,

    // Enlaces
    ...config,

    // Metadata
    processId,
    activationDate: new Date().toISOString(),

    // Datos originales para referencia
    _input: input
  }
}];

